import { NextResponse } from 'next/server';
import { tx } from '@/lib/db';
import { hashPassword } from '@/lib/auth';
import { setSession } from '@/lib/session';
import { buildSeedState } from '@/lib/seed';

export const runtime = 'nodejs';

export async function POST(req: Request) {
  let body: { email?: string; password?: string; name?: string; householdName?: string };
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: 'Invalid JSON' }, { status: 400 });
  }

  const email = String(body.email || '').trim().toLowerCase();
  const password = String(body.password || '');
  const name = String(body.name || '').trim();

  if (!/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(email)) {
    return NextResponse.json({ error: 'Enter a valid email address.' }, { status: 400 });
  }
  if (password.length < 8) {
    return NextResponse.json({ error: 'Password must be at least 8 characters.' }, { status: 400 });
  }
  if (!name) {
    return NextResponse.json({ error: 'Your name is required.' }, { status: 400 });
  }

  try {
    const userId = await tx(async (client) => {
      const existing = await client.query('SELECT 1 FROM users WHERE email = $1', [email]);
      if (existing.rowCount) {
        throw new Error('EMAIL_TAKEN');
      }
      const userRes = await client.query<{ id: string }>(
        'INSERT INTO users (email, password_hash) VALUES ($1, $2) RETURNING id',
        [email, hashPassword(password)],
      );
      const uid = userRes.rows[0].id;
      const state = buildSeedState(name, body.householdName);
      await client.query('INSERT INTO households (owner_user_id, state) VALUES ($1, $2)', [uid, state]);
      return uid;
    });

    await setSession(userId);
    return NextResponse.json({ ok: true, user: { id: userId, email, plan: 'free' } });
  } catch (err) {
    if (err instanceof Error && err.message === 'EMAIL_TAKEN') {
      return NextResponse.json({ error: 'That email is already registered.' }, { status: 409 });
    }
    // eslint-disable-next-line no-console
    console.error('register failed:', err);
    return NextResponse.json({ error: 'Could not create your account.' }, { status: 500 });
  }
}

// GET /api/cctv/clip?path= — stream a single recorded clip, Range-aware and
// path-guarded to the household's storage root. Cloud mode has no local clips,
// so we return 404 with a local-agent message.
import { getSessionUser } from '@/lib/session';
import { loadState } from '@/lib/state';
import { isCloud, LOCAL_AGENT_REQUIRED } from '@/lib/cctv/cloud';
import { can } from '@/lib/entitlements';
import { withinRoot } from '@/lib/cctv/paths';
import fs from 'node:fs';
import path from 'node:path';
import { Readable } from 'node:stream';
import type { ReadableStream as WebReadableStream } from 'node:stream/web';

export const runtime = 'nodejs';

interface StoredCctv {
  storagePath?: string;
}

function notFound(reason: string): Response {
  return new Response(JSON.stringify({ error: 'Clip not found', reason }), {
    status: 404,
    headers: { 'Content-Type': 'application/json' },
  });
}

export async function GET(req: Request) {
  const user = await getSessionUser();
  if (!user) {
    return new Response(JSON.stringify({ error: 'Unauthorized' }), {
      status: 401,
      headers: { 'Content-Type': 'application/json' },
    });
  }

  if (!can(user.plan, 'cctv')) return notFound('upgrade-required');

  if (isCloud()) return notFound(LOCAL_AGENT_REQUIRED);

  const state = await loadState(user.id);
  const cfg = state?.cctv as StoredCctv | undefined;
  const root = cfg?.storagePath || '';

  const url = new URL(req.url);
  const file = path.resolve(url.searchParams.get('path') || '');

  if (!root || !withinRoot(root, file) || !fs.existsSync(file)) return notFound('not found');

  const stat = fs.statSync(file);
  const range = req.headers.get('range');

  if (range) {
    const [s, e] = range.replace('bytes=', '').split('-');
    const start = parseInt(s, 10) || 0;
    const end = e ? parseInt(e, 10) : stat.size - 1;
    const nodeStream = fs.createReadStream(file, { start, end });
    const webStream = Readable.toWeb(nodeStream) as unknown as WebReadableStream<Uint8Array>;
    return new Response(webStream as unknown as ReadableStream, {
      status: 206,
      headers: {
        'Content-Range': `bytes ${start}-${end}/${stat.size}`,
        'Accept-Ranges': 'bytes',
        'Content-Length': String(end - start + 1),
        'Content-Type': 'video/mp4',
      },
    });
  }

  const nodeStream = fs.createReadStream(file);
  const webStream = Readable.toWeb(nodeStream) as unknown as WebReadableStream<Uint8Array>;
  return new Response(webStream as unknown as ReadableStream, {
    status: 200,
    headers: {
      'Content-Length': String(stat.size),
      'Content-Type': 'video/mp4',
      'Accept-Ranges': 'bytes',
    },
  });
}

// GET /api/cctv/clips?camera=&date= — list recorded clips from storage, newest
// first. Cloud mode has no local storage, so we return a `local-agent-required`
// shape with an empty list.
import { NextResponse } from 'next/server';
import { getSessionUser } from '@/lib/session';
import { loadState } from '@/lib/state';
import { isCloud, LOCAL_AGENT_REQUIRED } from '@/lib/cctv/cloud';
import { can } from '@/lib/entitlements';
import { listClips } from '@/lib/cctv/storage';
import { safeName } from '@/lib/cctv/paths';

export const runtime = 'nodejs';

interface StoredCctv {
  storagePath?: string;
}

export async function GET(req: Request) {
  const user = await getSessionUser();
  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  if (!can(user.plan, 'cctv'))
    return NextResponse.json({ error: 'Upgrade to Pro to use CCTV', upgrade: true }, { status: 403 });

  if (isCloud()) {
    return NextResponse.json({ ok: false, clips: [], reason: LOCAL_AGENT_REQUIRED });
  }

  const state = await loadState(user.id);
  const cfg = state?.cctv as StoredCctv | undefined;
  const root = cfg?.storagePath || '';
  if (!root) return NextResponse.json([]);

  const url = new URL(req.url);
  const cam = url.searchParams.get('camera');
  const date = url.searchParams.get('date');
  const slug = cam ? safeName(cam) : null;

  const clips = (await listClips(root))
    .filter((c) => {
      const p = c.path.replace(/\\/g, '/');
      if (slug && !p.includes(`/${slug}/`)) return false;
      if (date && !p.includes(`/${date}/`)) return false;
      return true;
    })
    .sort((a, b) => b.mtime - a.mtime)
    .map((c) => ({
      path: c.path,
      when: c.when ? c.when.toISOString() : null,
      sizeMB: +(c.size / (1024 * 1024)).toFixed(1),
    }));

  return NextResponse.json(clips);
}

// POST /api/cctv/config — save storage settings + cameras. New plaintext
// rtsp:// URLs are encrypted at rest; omitted URLs keep the camera's existing
// ciphertext. Saving works in cloud mode too (so users can pre-configure);
// only the live recording engine (applyConfig) is gated on self-hosting.
import { NextResponse } from 'next/server';
import { getSessionUser } from '@/lib/session';
import { loadState, saveState } from '@/lib/state';
import { encryptSecret, decryptSecret } from '@/lib/crypto';
import { isCloud } from '@/lib/cctv/cloud';
import { can } from '@/lib/entitlements';
import { applyConfig, sanitizeCamerasForClient, type Camera, type EngineConfig } from '@/lib/cctv';
import type { HouseholdState } from '@/lib/seed';
import { randomUUID } from 'node:crypto';

export const runtime = 'nodejs';

interface RawCamera {
  id?: string;
  name?: string;
  rtspUrl?: string;
  sensitivity?: number;
  preRoll?: number;
  postRoll?: number;
  enabled?: boolean;
}

interface ConfigBody {
  enabled?: boolean;
  storagePath?: string;
  freeSpaceFloorGB?: number;
  cameras?: RawCamera[];
}

interface StoredCctv {
  enabled?: boolean;
  storagePath?: string;
  freeSpaceFloorGB?: number;
  cameras?: Camera[];
}

export async function POST(req: Request) {
  const user = await getSessionUser();
  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  if (!can(user.plan, 'cctv'))
    return NextResponse.json({ error: 'Upgrade to Pro to use CCTV', upgrade: true }, { status: 403 });

  const state = await loadState(user.id);
  if (!state) return NextResponse.json({ error: 'Household not found' }, { status: 404 });

  let body: ConfigBody;
  try {
    body = await req.json();
  } catch {
    return NextResponse.json({ error: 'Invalid JSON' }, { status: 400 });
  }

  const prev: StoredCctv = (state.cctv as StoredCctv | undefined) || { cameras: [] };
  const prevById = new Map<string, Camera>((prev.cameras || []).map((c) => [c.id, c]));

  const cameras: Camera[] = [];
  for (const raw of Array.isArray(body.cameras) ? body.cameras : []) {
    const id = String(raw.id || randomUUID());
    const existing = prevById.get(id);
    let rtspUrl: string;
    if (typeof raw.rtspUrl === 'string' && raw.rtspUrl.trim()) {
      if (!/^rtsp:\/\//i.test(raw.rtspUrl.trim())) {
        return NextResponse.json(
          { error: `Camera "${raw.name || id}" stream URL must start with rtsp://` },
          { status: 400 },
        );
      }
      rtspUrl = encryptSecret(raw.rtspUrl.trim());
    } else if (existing) {
      rtspUrl = existing.rtspUrl; // keep stored ciphertext
    } else {
      return NextResponse.json(
        { error: `Camera "${raw.name || id}" needs an rtsp:// stream URL` },
        { status: 400 },
      );
    }
    cameras.push({
      id,
      name: String(raw.name || 'Camera').slice(0, 60),
      rtspUrl,
      sensitivity: Math.min(0.5, Math.max(0.005, Number(raw.sensitivity) || 0.04)),
      preRoll: Math.min(30, Math.max(0, Number(raw.preRoll) ?? 5)),
      postRoll: Math.min(60, Math.max(0, Number(raw.postRoll) ?? 8)),
      enabled: !!raw.enabled,
    });
  }

  const cctv: EngineConfig = {
    enabled: body.enabled !== undefined ? !!body.enabled : (prev.enabled ?? true),
    storagePath: String(body.storagePath ?? prev.storagePath ?? '').trim(),
    freeSpaceFloorGB: Math.max(1, Number(body.freeSpaceFloorGB) || prev.freeSpaceFloorGB || 20),
    cameras,
  };

  const next = { ...state, cctv } as HouseholdState;
  const ok = await saveState(user.id, next);
  if (!ok) return NextResponse.json({ error: 'Household not found' }, { status: 404 });

  // Apply to the live engine only when self-hosting (best-effort; never blocks
  // the response). In cloud mode the config is persisted but recording is off.
  if (!isCloud()) {
    applyConfig(cctv, { decrypt: decryptSecret }).catch(() => {});
  }

  return NextResponse.json({
    ok: true,
    cloud: isCloud(),
    cameras: sanitizeCamerasForClient(cameras, decryptSecret),
  });
}

// GET /api/cctv/status — ffmpeg availability, storage writability/free space,
// and cameras (RTSP masked). In cloud mode we short-circuit with a
// `local-agent-required` payload so the UI shows the self-hosting banner.
import { NextResponse } from 'next/server';
import { getSessionUser } from '@/lib/session';
import { loadState } from '@/lib/state';
import { decryptSecret } from '@/lib/crypto';
import { isCloud, LOCAL_AGENT_REQUIRED } from '@/lib/cctv/cloud';
import { can } from '@/lib/entitlements';
import {
  ffmpegInfo,
  cctvStatusPayload,
  sanitizeCamerasForClient,
  type Camera,
} from '@/lib/cctv';
import { validateStorage } from '@/lib/cctv/storage';

export const runtime = 'nodejs';

interface CctvCfg {
  enabled?: boolean;
  storagePath?: string;
  freeSpaceFloorGB?: number;
  cameras?: Camera[];
}

export async function GET() {
  const user = await getSessionUser();
  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

  // CCTV is a Pro feature — free plans get an upgrade prompt instead of config.
  if (!can(user.plan, 'cctv')) {
    return NextResponse.json({ ok: false, upgrade: true, reason: 'upgrade-required' });
  }

  const state = await loadState(user.id);
  const cfg: CctvCfg =
    (state?.cctv as CctvCfg | undefined) || { storagePath: '', freeSpaceFloorGB: 20, cameras: [] };
  const cameras = sanitizeCamerasForClient(cfg.cameras, decryptSecret);

  // Cloud: a hosted instance can't reach LAN cameras/NAS. Still return cameras
  // so the configuration UI stays usable; recording just won't run.
  if (isCloud()) {
    return NextResponse.json({
      ok: false,
      cloud: true,
      ffmpeg: false,
      ffprobe: false,
      reason: LOCAL_AGENT_REQUIRED,
      storage: { ok: false, reason: LOCAL_AGENT_REQUIRED, freeGB: 0 },
      enabled: !!cfg.enabled,
      cameras,
      storagePath: cfg.storagePath || '',
      freeSpaceFloorGB: cfg.freeSpaceFloorGB || 20,
    });
  }

  // Self-host: probe ffmpeg + storage for real.
  const ff = await ffmpegInfo();
  const storage = cfg.storagePath
    ? await validateStorage(cfg.storagePath)
    : { ok: false, reason: 'not configured', freeBytes: 0 };

  const payload = cctvStatusPayload(ff, storage, { enabled: cfg.enabled, cameras });
  return NextResponse.json({
    ok: true,
    cloud: false,
    ...payload,
    storagePath: cfg.storagePath || '',
    freeSpaceFloorGB: cfg.freeSpaceFloorGB || 20,
  });
}

// POST /api/cctv/test { rtspUrl } — probe an RTSP stream before enabling it.
// In cloud mode there's no LAN/ffmpeg, so we return `local-agent-required`.
import { NextResponse } from 'next/server';
import { getSessionUser } from '@/lib/session';
import { isCloud, LOCAL_AGENT_REQUIRED } from '@/lib/cctv/cloud';
import { can } from '@/lib/entitlements';
import { validateRtspUrl } from '@/lib/cctv';

export const runtime = 'nodejs';

export async function POST(req: Request) {
  const user = await getSessionUser();
  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  if (!can(user.plan, 'cctv'))
    return NextResponse.json({ error: 'Upgrade to Pro to use CCTV', upgrade: true }, { status: 403 });

  if (isCloud()) {
    return NextResponse.json({ ok: false, reason: LOCAL_AGENT_REQUIRED });
  }

  let body: { rtspUrl?: string };
  try {
    body = await req.json();
  } catch {
    body = {};
  }
  const result = await validateRtspUrl(String(body.rtspUrl || ''));
  return NextResponse.json(result);
}

// /api/discover — LAN smart-device discovery (zero-dep SSDP/UPnP).
//   GET            → scan the local network for devices.
//   POST { check } → probe a single host for TCP reachability.
// Cloud mode can't reach a user's home LAN, so both return
// `local-agent-required` shapes (and the Connect-Devices UI degrades cleanly).
import { NextResponse } from 'next/server';
import { getSessionUser } from '@/lib/session';
import { isCloud, LOCAL_AGENT_REQUIRED } from '@/lib/cctv/cloud';
import { can } from '@/lib/entitlements';
import { discoverDevices, checkReachable, isPrivateHost } from '@/lib/discovery';

export const runtime = 'nodejs';

const UPGRADE_REASON = 'Device discovery is a Pro feature — upgrade to scan your network.';

export async function GET() {
  const user = await getSessionUser();
  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

  if (!can(user.plan, 'discovery')) {
    return NextResponse.json({ ok: false, upgrade: true, reason: UPGRADE_REASON, devices: [] });
  }

  if (isCloud()) {
    return NextResponse.json({ ok: false, reason: LOCAL_AGENT_REQUIRED, devices: [] });
  }

  const result = await discoverDevices({ timeoutMs: 4000 });
  return NextResponse.json(result);
}

export async function POST(req: Request) {
  const user = await getSessionUser();
  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

  if (!can(user.plan, 'discovery')) {
    return NextResponse.json({ ok: false, upgrade: true, reason: UPGRADE_REASON, devices: [] });
  }

  let body: { check?: string };
  try {
    body = await req.json();
  } catch {
    body = {};
  }

  if (body.check) {
    if (isCloud()) {
      return NextResponse.json({ reachable: false, reason: LOCAL_AGENT_REQUIRED });
    }
    const [host, portStr] = String(body.check).split(':');
    // Restrict probes to private/LAN ranges — refusing public/link-local hosts
    // prevents the server being used as an SSRF port-scanner (cloud metadata).
    if (!isPrivateHost(host)) {
      return NextResponse.json({ reachable: false, host, error: 'Only private (LAN) addresses can be probed' });
    }
    const reachable = await checkReachable(host, Number(portStr) || 80);
    return NextResponse.json({ reachable, host });
  }

  if (isCloud()) {
    return NextResponse.json({ ok: false, reason: LOCAL_AGENT_REQUIRED, devices: [] });
  }
  const result = await discoverDevices({ timeoutMs: 4000 });
  return NextResponse.json(result);
}

import { NextResponse } from 'next/server';
import { getSessionUser } from '@/lib/session';
import { loadState, saveState } from '@/lib/state';
import type { HouseholdState } from '@/lib/seed';

export const runtime = 'nodejs';

export async function GET() {
  const user = await getSessionUser();
  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  const state = await loadState(user.id);
  if (!state) return NextResponse.json({ error: 'No household' }, { status: 404 });
  return NextResponse.json({ state, plan: user.plan });
}

export async function PUT(req: Request) {
  const user = await getSessionUser();
  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  let state: HouseholdState;
  try {
    state = await req.json();
  } catch {
    return NextResponse.json({ error: 'Invalid JSON' }, { status: 400 });
  }
  if (!state || typeof state !== 'object' || Array.isArray(state)) {
    return NextResponse.json({ error: 'Invalid state' }, { status: 400 });
  }
  const ok = await saveState(user.id, state);
  if (!ok) return NextResponse.json({ error: 'No household' }, { status: 404 });
  return NextResponse.json({ ok: true });
}

import { NextResponse } from 'next/server';
import { getSessionUser } from '@/lib/session';
import { getStripe, getOrCreateCustomer, getProPriceId } from '@/lib/stripe';

export const runtime = 'nodejs';

export async function POST() {
  const user = await getSessionUser();
  if (!user) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

  const appUrl = process.env.NEXT_PUBLIC_APP_URL;
  if (!appUrl) return NextResponse.json({ error: 'NEXT_PUBLIC_APP_URL is not set' }, { status: 500 });

  try {
    const customer = await getOrCreateCustomer(user);
    const session = await getStripe().checkout.sessions.create({
      mode: 'subscription',
      customer,
      line_items: [{ price: getProPriceId(), quantity: 1 }],
      allow_promotion_codes: true,
      success_url: `${appUrl}/app/billing?success=1`,
      cancel_url: `${appUrl}/app/billing?canceled=1`,
      metadata: { userId: user.id },
    });

    if (!session.url) {
      return NextResponse.json({ error: 'Failed to create checkout session' }, { status: 500 });
    }
    return NextResponse.json({ url: session.url });
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Checkout failed';
    return NextResponse.json({ error: message }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import { getSessionUser } from '@/lib/session';
import { getStripe, getOrCreateCustomer } from '@/lib/stripe';

export const runtime = 'nodejs';

