export type AuthMode = 'login' | 'register';

export function AuthCard({ mode }: { mode: AuthMode }) {
  const router = useRouter();
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState('');

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [householdName, setHouseholdName] = useState('');

  async function submit(e: React.FormEvent) {
    e.preventDefault();
    if (busy) return;
    setBusy(true);
    setError('');
    const path = mode === 'login' ? '/api/auth/login' : '/api/auth/register';
    const body =
      mode === 'login'
        ? { email: email.trim(), password }
        : { name: name.trim(), householdName: householdName.trim(), email: email.trim(), password };
    try {
      const res = await fetch(path, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      });
      const text = await res.text();
      let data: { error?: string } = {};
      try {
        data = text ? JSON.parse(text) : {};
      } catch {
        /* ignore */
      }
      if (!res.ok) {
        setError(data.error || (mode === 'login' ? 'Sign in failed' : 'Could not create account'));
        setBusy(false);
        return;
      }
      router.push('/app');
      router.refresh();
    } catch {
      setError('Network error — please try again.');
      setBusy(false);
    }
  }

  return (
    <div className="relative z-10 min-h-screen flex items-center justify-center" style={{ padding: 20 }}>
      <div className="card auth-card relative z-10">
        <ArtPanel />
        <div className="auth-form">
          <div className="flex items-center gap-3 mb-5">
            <div className="w-9 h-9 rounded-xl bg-gradient-to-br from-emerald-500 to-teal-600 flex items-center justify-center">
              <i className="fa-solid fa-house-chimney text-white text-sm" />
            </div>
            <div>
              <h2 className="text-lg font-bold" style={{ fontFamily: "'Space Grotesk'" }}>
                Welcome
              </h2>
              <p className="text-[11px] text-[var(--muted)] -mt-0.5">Sign in to your household</p>
            </div>
          </div>
          <div className="flex gap-2 mb-4">
            <Link
              href="/login"
              className={`sec-tab ${mode === 'login' ? 'active' : ''}`}
              prefetch={false}
            >
              Sign in
            </Link>
            <Link
              href="/register"
              className={`sec-tab ${mode === 'register' ? 'active' : ''}`}
              prefetch={false}
            >
              Create account
            </Link>
          </div>
          {error && (
            <div
              className="mb-3 px-3 py-2 rounded-lg text-xs"
              style={{
                background: 'rgba(239,68,68,.12)',
                color: 'var(--red)',
                border: '1px solid rgba(239,68,68,.3)',
              }}
              role="alert"
            >
              {error}
            </div>
          )}
          <form onSubmit={submit}>
            <div className="space-y-3">
              {mode === 'register' && (
                <>
                  <div>
                    <label>Your name</label>
                    <input
                      className="input"
                      value={name}
                      onChange={(e) => setName(e.target.value)}
                      placeholder="e.g. Marcus"
                      required
                    />
                  </div>
                  <div>
                    <label>
                      Household name <span className="font-normal text-[var(--muted)]">(optional)</span>
                    </label>
                    <input
                      className="input"
                      value={householdName}
                      onChange={(e) => setHouseholdName(e.target.value)}
                      placeholder="The Cantila Home"
                    />
                  </div>
                </>
              )}
              <div>
                <label>Email</label>
                <input
                  className="input"
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  autoComplete="email"
                  required
                />
              </div>
              <div>
                <label>Password</label>
                <input
                  className="input"
                  type="password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  autoComplete={mode === 'login' ? 'current-password' : 'new-password'}
                  placeholder={mode === 'register' ? 'At least 8 characters' : undefined}
                  required
                />
              </div>
              <button className="btn btn-primary w-full" type="submit" disabled={busy}>
                {mode === 'login' ? 'Sign in' : 'Create account'}
              </button>
            </div>
          </form>
          <p className="text-[11px] text-[var(--muted)] text-center mt-4">
            Register with any email — your hub is stored on this server, ready with starter rooms,
            scenes &amp; automations to explore.
          </p>
        </div>
      </div>
    </div>
  );
}

'use client';

import { useEffect, useState } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { useHousehold } from '@/store/household';

interface Props {
  plan: 'free' | 'pro';
  status: string | null;
  periodEnd: string | null;
}

const PRO_FEATURES = [
  { ic: 'fa-house-signal', t: 'Smart-home device control' },
  { ic: 'fa-wand-magic-sparkles', t: 'Automations & scenes' },
  { ic: 'fa-video', t: 'CCTV recording & storage' },
  { ic: 'fa-microphone', t: 'Voice assistant control' },
  { ic: 'fa-wifi', t: 'Device discovery & pairing' },
  { ic: 'fa-users', t: 'Unlimited family members' },
];

export function BillingClient({ plan, status, periodEnd }: Props) {
  const { toast } = useHousehold();
  const router = useRouter();
  const params = useSearchParams();
  const [busy, setBusy] = useState<'checkout' | 'portal' | null>(null);

  const isPro = plan === 'pro';

  // Surface the Stripe redirect result once, then clean the URL.
  useEffect(() => {
    if (params.get('success')) {
      toast('Welcome to Pro! Your smart home is unlocked.', 'success');
      router.replace('/app/billing');
      router.refresh();
    } else if (params.get('canceled')) {
      toast('Checkout canceled — no charge was made.', 'info');
      router.replace('/app/billing');
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  async function go(kind: 'checkout' | 'portal') {
    if (busy) return;
    setBusy(kind);
    try {
      const res = await fetch(`/api/stripe/${kind}`, { method: 'POST' });
      const data = await res.json().catch(() => ({}));
      if (!res.ok || !data.url) throw new Error(data.error || 'Something went wrong');
      window.location.href = data.url;
    } catch (e) {
      toast(e instanceof Error ? e.message : 'Something went wrong', 'error');
      setBusy(null);
    }
  }

  return (
    <div className="max-w-2xl mx-auto space-y-5">
      {/* Current plan */}
      <div className="card p-6">
        <div className="flex items-center justify-between mb-4">
          <div>
            <div className="text-xs text-[var(--muted)] uppercase tracking-wide mb-1">Current plan</div>
            <div className="flex items-center gap-2.5">
              <h2 className="text-2xl font-bold" style={{ fontFamily: 'Space Grotesk' }}>
                {isPro ? 'Pro' : 'Free'}
              </h2>
              {isPro && (
                <span
                  className="text-[10px] font-bold uppercase tracking-wide px-2.5 py-1 rounded-full"
                  style={{ background: 'var(--accent-g)', color: 'var(--accent)' }}
                >
                  Active
                </span>
              )}
            </div>
          </div>
          <div
            className="w-12 h-12 rounded-2xl flex items-center justify-center"
            style={{ background: 'var(--accent-g)' }}
          >
            <i className={`fa-solid ${isPro ? 'fa-crown' : 'fa-house'} text-lg`} style={{ color: 'var(--accent)' }} />
          </div>
        </div>

        {isPro ? (
          <>
            <p className="text-sm text-[var(--muted)]">
              You have full access to the connected smart home.
              {status && status !== 'active' && (
                <span className="text-[var(--amber)]"> Subscription status: {status}.</span>
              )}
              {periodEnd && <> Renews {new Date(periodEnd).toLocaleDateString()}.</>}
            </p>
            <button className="btn btn-secondary mt-5" onClick={() => go('portal')} disabled={busy !== null}>
              <i className="fa-solid fa-gear" />
              {busy === 'portal' ? 'Opening…' : 'Manage subscription'}
            </button>
          </>
        ) : (
          <p className="text-sm text-[var(--muted)]">
            You&apos;re on the free plan — the full family hub for calendar, finance, chores, and family.
            Upgrade to unlock the connected smart home.
          </p>
        )}
      </div>

