            <div className="prog-fill" style={{ width: util + '%', background: util > 70 ? 'var(--red)' : util > 30 ? 'var(--amber)' : 'var(--accent)' }} />
          </div>
          <div className="flex justify-between text-[10px] text-[var(--muted)] mb-3">
