// Automation engine — pure functions that mutate a HouseholdState draft. Ported
// from the legacy automations.js. The rule-builder + Connect-Devices UI lives in
// the React Home view; this module is the headless engine it (and the store) call.
import type { HouseholdState, Scene, Automation, SceneActions, AutomationTrigger } from './types';

function nowHM(): string {
  const d = new Date();
  return String(d.getHours()).padStart(2, '0') + ':' + String(d.getMinutes()).padStart(2, '0');
}
function todayKey(): string {
  const d = new Date();
  return d.getFullYear() + '-' + d.getMonth() + '-' + d.getDate();
}

// Once-per-scheduled-minute dedupe for the time tick (client-runtime memory).
const firedKeys = new Set<string>();

export function presenceMatch(state: HouseholdState, mode: string): boolean {
  const members = state.members || [];
  if (!members.length) return false;
  const away = members.every((m) => ['out', 'work', 'school', 'gym'].includes(m.status));
  const anyHome = members.some((m) => m.status === 'home');
  if (mode === 'everyone_away') return away;
  if (mode === 'someone_home') return anyHome;
  return false;
}

// Apply a scene's action map to the draft (used by both the UI scene buttons and the engine).
export function applySceneActions(d: HouseholdState, a: SceneActions): void {
  if (a.lightsAllOff) d.lights.forEach((l) => (l.on = false));
  if (a.lightsOn) a.lightsOn.forEach((rm) => d.lights.filter((l) => l.room === rm).forEach((l) => { l.on = true; l.brightness = 80; }));
  if (a.lightsDim) d.lights.filter((l) => l.on).forEach((l) => (l.brightness = Math.min(l.brightness, a.lightsDim!)));
  if (a.devicesOn) a.devicesOn.forEach((id) => { const dev = d.devices.find((x) => x.id === id); if (dev) dev.status = 'on'; });
  if (a.lockAll) d.devices.filter((dv) => dv.type === 'lock').forEach((dv) => { dv.status = 'locked'; dv.icon = 'fa-lock'; });
  if (a.arm) d.securityArmed = true;
  if (a.thermostat) { d.thermostat.target = a.thermostat; d.thermostat.on = true; }
}

function applyAutomationActions(d: HouseholdState, auto: Automation): void {
  (auto.actions || []).forEach((ac) => {
    if (ac.kind === 'scene') {
      const sc = d.scenes.find((s) => s.id === ac.scene);
      if (sc) applySceneActions(d, sc.actions);
    } else if (ac.kind === 'lights') {
      const ls = ac.room === 'all' || !ac.room ? d.lights : d.lights.filter((l) => l.room === ac.room);
      ls.forEach((l) => { l.on = !!ac.on; if (ac.on && l.brightness < 5) l.brightness = 80; });
    } else if (ac.kind === 'lightsOff') {
      d.lights.forEach((l) => (l.on = false));
    } else if (ac.kind === 'thermostat') {
      const t = ac as { target?: number };
      d.thermostat.target = Math.max(55, Math.min(85, +(t.target ?? 70) || 70));
      d.thermostat.on = true;
    } else if (ac.kind === 'security') {
      d.securityArmed = !!ac.arm;
    } else if (ac.kind === 'lockAll') {
      d.devices.filter((dv) => dv.type === 'lock').forEach((dv) => { dv.status = 'locked'; dv.icon = 'fa-lock'; });
    }
  });
}

export function fireAutomation(d: HouseholdState, auto: Automation): void {
  applyAutomationActions(d, auto);
  auto.lastRun = 'Just now';
  d.alerts.unshift({ id: ++d.nid, type: 'automation', msg: 'Automation “' + auto.name + '” ran', time: 'Just now', sev: 'info', seen: false });
}

// Event-driven triggers (security/presence). Returns whether any rule fired.
export function runAutomations(d: HouseholdState, event: { type: string; armed?: boolean }): boolean {
  let fired = false;
  (d.automations || []).forEach((auto) => {
    if (!auto.enabled) return;
    const tg = auto.trigger as AutomationTrigger;
    if (tg.type !== event.type) return;
    if (tg.type === 'security' && !!tg.armed !== !!event.armed) return;
    if (tg.type === 'presence' && !presenceMatch(d, tg.mode)) return;
    fireAutomation(d, auto);
    fired = true;
  });
  return fired;
}

// Time-driven triggers — called once a minute. Returns whether any rule fired.
export function tickAutomations(d: HouseholdState): boolean {
  const hm = nowHM();
  const tk = todayKey();
  let fired = false;
  (d.automations || []).forEach((auto) => {
    if (!auto.enabled) return;
    const tg = auto.trigger as AutomationTrigger;
    if (tg.type !== 'time' || tg.at !== hm) return;
    const key = auto.id + ':' + tk + ' ' + hm;
    if (firedKeys.has(key)) return;
    firedKeys.add(key);
    fireAutomation(d, auto);
    fired = true;
  });
  return fired;
}

export function defaultAutomations(d: HouseholdState): Automation[] {
  return [
    { id: ++d.nid, name: 'Good Night', icon: 'fa-moon', enabled: true, trigger: { type: 'time', at: '23:00' }, actions: [{ kind: 'scene', scene: 'bedtime' }], lastRun: null },
    { id: ++d.nid, name: 'Wake Up', icon: 'fa-sun', enabled: true, trigger: { type: 'time', at: '07:00' }, actions: [{ kind: 'scene', scene: 'morning' }], lastRun: null },
    { id: ++d.nid, name: 'Secure When Everyone Leaves', icon: 'fa-shield-halved', enabled: true, trigger: { type: 'presence', mode: 'everyone_away' }, actions: [{ kind: 'lightsOff' }, { kind: 'lockAll' }, { kind: 'security', arm: true }], lastRun: null },
    { id: ++d.nid, name: 'Welcome Home', icon: 'fa-house-chimney-window', enabled: true, trigger: { type: 'presence', mode: 'someone_home' }, actions: [{ kind: 'security', arm: false }, { kind: 'lights', room: 'all', on: true }], lastRun: null },
    { id: ++d.nid, name: 'Lights Out Overnight', icon: 'fa-bolt', enabled: false, trigger: { type: 'time', at: '01:00' }, actions: [{ kind: 'lightsOff' }], lastRun: null },
  ];
}

export const TRIGGER_TEXT = (tg: AutomationTrigger): string => {
  if (!tg) return '';
  if (tg.type === 'time') return 'Every day at ' + tg.at;
  if (tg.type === 'security') return tg.armed ? 'When security is armed' : 'When security is disarmed';
  if (tg.type === 'presence') return tg.mode === 'everyone_away' ? 'When everyone leaves home' : 'When someone comes home';
  return '';
};

export function actionText(state: HouseholdState, actions: Automation['actions']): string {
  return (actions || [])
    .map((ac) => {
      if (ac.kind === 'scene') { const sc = state.scenes.find((s) => s.id === ac.scene); return 'Run “' + (sc ? sc.name : ac.scene) + '”'; }
      if (ac.kind === 'lights') return 'Turn lights ' + (ac.on ? 'on' : 'off');
      if (ac.kind === 'lightsOff') return 'All lights off';
      if (ac.kind === 'thermostat') return 'Set climate to ' + (ac as { target?: number }).target + '°';
      if (ac.kind === 'security') return ac.arm ? 'Arm security' : 'Disarm security';
      if (ac.kind === 'lockAll') return 'Lock all doors';
      return '';
    })
    .filter(Boolean)
    .join(' · ');
}

export type { Scene };

// Cloud-awareness for the CCTV feature. A cloud instance cannot reach cameras
// or NAS storage on a user's home LAN, so the recording engine is gated behind
// isCloud(). When cloud, the APIs return a `local-agent-required` state and the
// UI shows a "requires self-hosting" banner.
//
// Node built-ins only — safe in route handlers (runtime='nodejs'). Detection is
// lazy/memoized so importing this module never spawns a process or throws.
import { spawnSync } from 'node:child_process';
import fs from 'node:fs';
import path from 'node:path';

export const LOCAL_AGENT_REQUIRED = 'local-agent-required';

let ffmpegCache: boolean | null = null;

// True iff ffmpeg is invocable. Checks FFMPEG_PATH (if it points at a real file)
// first, then resolves `ffmpeg` on PATH via `which`/`where`. Memoized; never
// throws. Synchronous on purpose so callers can use it inside other guards.
export function ffmpegAvailable(): boolean {
  if (ffmpegCache !== null) return ffmpegCache;
  ffmpegCache = detectFfmpeg();
  return ffmpegCache;
}

function detectFfmpeg(): boolean {
  const explicit = process.env.FFMPEG_PATH;
  if (explicit) {
    // An explicit path is trusted if it exists; else fall through to PATH lookup.
    try {
      if (fs.existsSync(explicit) && fs.statSync(explicit).isFile()) return true;
    } catch {
      /* ignore and try PATH */
    }
  }
  // `which ffmpeg` (POSIX) / `where ffmpeg` (Windows). spawnSync never throws on
  // a missing binary — it sets .error / non-zero status instead.
  const finder = process.platform === 'win32' ? 'where' : 'which';
  try {
    const r = spawnSync(finder, ['ffmpeg'], { stdio: 'ignore' });
    if (!r.error && r.status === 0) return true;
  } catch {
    /* ignore */
  }
  // Last resort: probe `ffmpeg -version` directly (covers shells where which is
  // absent but ffmpeg is on PATH).
  const bin = explicit || 'ffmpeg';
  try {
    const r = spawnSync(bin, ['-version'], { stdio: 'ignore' });
    if (!r.error && r.status === 0) return true;
  } catch {
    /* ignore */
  }
  return false;
}

// Cloud mode when explicitly flagged OR when ffmpeg isn't available (a cloud
// host won't have ffmpeg + LAN access for recording). Lazy: only reads env and
// probes ffmpeg when called, so `next build` never trips on import.
export function isCloud(): boolean {
  if (process.env.HOMEPAL_CLOUD === '1') return true;
  return !ffmpegAvailable();
}

// Where staging segments live for self-hosted recording. Kept here so both the
// engine and (future) tests share one definition. Outside the storage root so a
// retention sweep can't touch it.
export function stagingRoot(): string {
  return path.join(process.cwd(), 'data', 'cctv-staging');
}

// Pure functions: parse ffmpeg metadata.print output for scene-change times,
// and select staging segments that belong to a motion event window. No I/O.
// Ported from server/cctv-detect.js.

export interface Segment {
  file: string;
  start: number;
  end: number;
}

// metadata=print emits "pts_time:<sec>" lines followed by "lavfi.scene_score=..".
// Because the detector uses select='gt(scene,THRESH)', every emitted frame IS a
// motion frame, so we just collect the pts_time values.
export function parseSceneTimes(stderr: string): number[] {
  const out: number[] = [];
  const re = /pts_time:([0-9]+(?:\.[0-9]+)?)/g;
  let m: RegExpExecArray | null;
  while ((m = re.exec(String(stderr)))) out.push(Number(m[1]));
  return out;
}

// segments: [{file, start, end}] (seconds, monotonic). motionTimes: number[].
// opts: { preRoll, postRoll } seconds. Returns segments overlapping the union
// window [min(motion)-preRoll, max(motion)+postRoll].
export function selectSegments(
  segments: Segment[],
  motionTimes: number[],
  { preRoll = 5, postRoll = 8 }: { preRoll?: number; postRoll?: number } = {},
): Segment[] {
  if (!motionTimes.length) return [];
  const lo = Math.min(...motionTimes) - preRoll;
  const hi = Math.max(...motionTimes) + postRoll;
  return segments.filter((s) => s.end > lo && s.start < hi);
}

// CCTV recording engine + response shaping. Ported from server/cctv.js and
// server/cctv-api.js for SELF-HOST use. Node built-ins + ffmpeg/ffprobe child
// processes only — safe inside route handlers (runtime='nodejs').
//
// In cloud mode the routes short-circuit before touching the engine; nothing
// here spawns a process at import time, so `next build` is unaffected.
import { spawn, type ChildProcess } from 'node:child_process';
import fs from 'node:fs';
import fsp from 'node:fs/promises';
import path from 'node:path';
import { parseSceneTimes, selectSegments, type Segment } from './detect.ts';
import { clipRelPath } from './paths.ts';
import { validateStorage, listClips, planRetention, safeDelete } from './storage.ts';
import { stagingRoot } from './cloud.ts';
import { maskRtsp, decryptSecret } from '../crypto.ts';

const FFMPEG = process.env.FFMPEG_PATH || 'ffmpeg';
const FFPROBE = process.env.FFPROBE_PATH || 'ffprobe';
const RING_KEEP_SEC = 30; // trailing staging window to keep when idle
const GB = 1024 ** 3;

// ---- types ----

export interface Camera {
  id: string;
  name: string;
  rtspUrl: string; // ciphertext at rest
  sensitivity: number;
  preRoll: number;
  postRoll: number;
  enabled: boolean;
}

export interface EngineConfig {
  enabled: boolean;
  storagePath: string;
  freeSpaceFloorGB: number;
  cameras: Camera[];
}

interface LastClip {
  rel: string;
  at: string;
}

// ---- ffmpeg detection + rtsp validation ----

function probeBinary(bin: string): Promise<boolean> {
  return new Promise((resolve) => {
    let p: ChildProcess;
    try {
      p = spawn(bin, ['-version'], { stdio: 'ignore' });
    } catch {
      return resolve(false);
    }
    p.on('error', () => resolve(false));
    p.on('close', (code) => resolve(code === 0));
  });
}

export async function ffmpegInfo(): Promise<{ ffmpeg: boolean; ffprobe: boolean }> {
  const [ffmpeg, ffprobe] = await Promise.all([probeBinary(FFMPEG), probeBinary(FFPROBE)]);
  return { ffmpeg, ffprobe };
}

export interface RtspProbeResult {
  ok: boolean;
  reason?: string;
}

// Validate an RTSP URL: scheme check (no spawn), then a 1s ffmpeg decode to
// confirm the stream is reachable and decodable.
export async function validateRtspUrl(url: string, timeoutMs = 8000): Promise<RtspProbeResult> {
  if (!/^rtsp:\/\//i.test(String(url))) return { ok: false, reason: 'URL must start with rtsp://' };
  return new Promise((resolve) => {
    const args = ['-rtsp_transport', 'tcp', '-i', String(url), '-t', '1', '-f', 'null', '-'];
    let p: ChildProcess | undefined;
    let done = false;
    const finish = (v: RtspProbeResult) => {
      if (!done) {
        done = true;
        try {
          p?.kill('SIGKILL');
        } catch {
          /* ignore */
        }
        resolve(v);
      }
    };
    try {
      p = spawn(FFMPEG, args);
    } catch (e) {
      return resolve({ ok: false, reason: String((e as Error).message || e) });
    }
    let err = '';
    p.stderr?.on('data', (d: Buffer) => {
      err += d;
      if (err.length > 8192) err = err.slice(-8192);
    });
    p.on('error', (e) => finish({ ok: false, reason: String(e.message || e) }));
    p.on('close', (code) =>
      finish(
        code === 0
          ? { ok: true }
          : { ok: false, reason: err.split('\n').filter(Boolean).pop() || 'ffmpeg failed' },
      ),
    );
    setTimeout(() => finish({ ok: false, reason: 'timed out probing stream' }), timeoutMs);
  });
}

// ---- camera controller: motion-event stitching ----

type ConcatFn = (files: string[], outPath: string) => Promise<void>;

// Fed segment + motion events; emits a stitched clip via injected `concat`.
// No ffmpeg/timers here so it unit-tests in isolation.
export class CameraController {
  camera: Camera;
  concat: ConcatFn;
  storageRoot: string;
  now: () => Date;
  segments: Segment[] = [];
  motions: number[] = [];
  eventOpen = false;
  eventStartedAt: Date | null = null;
  lastMotion = -Infinity;
  lastClip: LastClip | null = null;

  constructor({
    camera,
    concat,
    storageRoot,
    now,
  }: {
    camera: Camera;
    concat: ConcatFn;
    storageRoot: string;
    now?: () => Date;
  }) {
    this.camera = camera;
    this.concat = concat;
    this.storageRoot = storageRoot;
    this.now = now || (() => new Date());
  }

  onMotion(t: number): void {
    this.motions.push(t);
    this.lastMotion = Math.max(this.lastMotion, t);
    if (!this.eventOpen) {
      this.eventOpen = true;
      this.eventStartedAt = this.now();
    }
  }

  async onSegment(seg: Segment): Promise<void> {
    this.segments.push(seg);
    const post = this.camera.postRoll ?? 8;
    if (this.eventOpen && seg.start > this.lastMotion + post) {
      await this._closeEvent();
    }
    this._trim();
  }

  _trim(): void {
    if (this.eventOpen) return; // keep everything while recording
    const cutoff = (this.segments.at(-1)?.end ?? 0) - RING_KEEP_SEC;
    this.segments = this.segments.filter((s) => s.end >= cutoff);
  }

  async _closeEvent(): Promise<string | null> {
    const picked = selectSegments(this.segments, this.motions, {
      preRoll: this.camera.preRoll ?? 5,
      postRoll: this.camera.postRoll ?? 8,
    });
    const startedAt = this.eventStartedAt || this.now();
    this.eventOpen = false;
    this.motions = [];
    this.lastMotion = -Infinity;
    if (!picked.length) return null;
    const rel = clipRelPath(this.camera.name, startedAt);
    const outPath = path.join(this.storageRoot, rel);
    await this.concat(
      picked.map((s) => s.file),
      outPath,
    );
    this.lastClip = { rel, at: startedAt.toISOString() };
    return outPath;
  }

  // Force-close any open event (shutdown / test).
  async flush(): Promise<void> {
    if (this.eventOpen) await this._closeEvent();
  }
}

// ---- ffmpeg adapters ----

// Concatenate MPEG-TS segments into one MP4 via ffmpeg concat demuxer.
export async function concatSegments(files: string[], outPath: string): Promise<void> {
  await fsp.mkdir(path.dirname(outPath), { recursive: true });
  const listFile = outPath + '.txt';
  await fsp.writeFile(listFile, files.map((f) => `file '${f.replace(/'/g, "'\\''")}'`).join('\n'));
  await new Promise<void>((resolve, reject) => {
    const p = spawn(
      FFMPEG,
      ['-y', '-f', 'concat', '-safe', '0', '-i', listFile, '-c', 'copy', '-movflags', '+faststart', outPath],
      { stdio: 'ignore' },
    );
    p.on('error', reject);
    p.on('close', (code) => (code === 0 ? resolve() : reject(new Error('concat failed code ' + code))));
  });
  await fsp.rm(listFile, { force: true });
}

// Spawn the segmenter: 2s -c copy MPEG-TS segments into stagingDir.
export function startSegmenter(url: string, stagingDir: string): ChildProcess {
  fs.mkdirSync(stagingDir, { recursive: true });
  const pattern = path.join(stagingDir, 'seg_%05d.ts');
  const p = spawn(
    FFMPEG,
    ['-rtsp_transport', 'tcp', '-i', url, '-an', '-c', 'copy', '-f', 'segment', '-segment_time', '2', '-reset_timestamps', '1', pattern],
    { stdio: ['ignore', 'ignore', 'ignore'] },
  );
  p.on('error', () => {}); // missing binary / spawn failure shouldn't crash the server
  return p;
}

// Spawn the detector: downscaled scene-change; emits motion times via onMotion.
export function startDetector(
  url: string,
  sensitivity: number,
  onMotion: (t: number) => void,
): ChildProcess {
  const p = spawn(
    FFMPEG,
    [
      '-rtsp_transport',
      'tcp',
      '-i',
      url,
      '-an',
      '-vf',
      `scale=320:-1,select='gt(scene,${Number(sensitivity) || 0.04})',metadata=print`,
      '-f',
      'null',
      '-',
    ],
    { stdio: ['ignore', 'ignore', 'pipe'] },
  );
  p.on('error', () => {}); // missing binary / spawn failure shouldn't crash the server
  let buf = '';
  p.stderr?.on('data', (d: Buffer) => {
    buf += d;
    const lines = buf.split('\n');
    buf = lines.pop() ?? '';
    for (const t of parseSceneTimes(lines.join('\n'))) onMotion(t);
  });
  return p;
}

// ---- engine orchestration + retention ----

// Run one retention pass. `space` ({freeBytes, floorBytes}) is provided by the
// caller (the sweep reads it via validateStorage; tests inject it).
export async function runRetention(
  root: string,
  space: { freeBytes: number; floorBytes: number },
): Promise<string[]> {
  if (!space) throw new Error('space required');
  const { freeBytes, floorBytes } = space;
  const clips = await listClips(root);
  const toDelete = planRetention(
    clips.map((c) => ({ path: c.path, mtime: c.mtime, size: c.size })),
    { freeBytes, floorBytes },
  );
  const deleted: string[] = [];
  for (const c of toDelete) if (await safeDelete(root, c.path)) deleted.push(c.path);
  return deleted;
}

interface Recorder {
  seg: ChildProcess;
  det: ChildProcess;
  ctrl: CameraController;
  stagingDir: string;
  watcher: fs.FSWatcher | null;
}

const recorders = new Map<string, Recorder>(); // cameraId -> recorder
let retentionTimer: ReturnType<typeof setInterval> | null = null;
let engineCfg: EngineConfig = { enabled: false, storagePath: '', freeSpaceFloorGB: 20, cameras: [] };

export function getEngineStatus() {
  return {
    enabled: engineCfg.enabled,
    storagePath: engineCfg.storagePath,
    freeSpaceFloorGB: engineCfg.freeSpaceFloorGB,
    cameras: [...recorders.values()].map((r) => ({
      id: r.ctrl.camera.id,
      name: r.ctrl.camera.name,
      recording: r.ctrl.eventOpen,
      lastClip: r.ctrl.lastClip || null,
    })),
  };
}

// (Re)configure the engine from a config object whose camera rtspUrls are
// ciphertext. Stops removed recorders, starts enabled ones, and (re)arms the
// retention sweep. `decrypt` turns a camera's stored rtspUrl into plaintext.
export async function applyConfig(
  cfg: EngineConfig,
  { decrypt = decryptSecret }: { decrypt?: (enc: string) => string } = {},
): Promise<void> {
  engineCfg = { ...engineCfg, ...cfg };
  const cameras = cfg.cameras || [];

  // Stop recorders that are gone or disabled.
  for (const [id, r] of recorders) {
    if (!cfg.enabled || !cameras.find((c) => c.id === id && c.enabled)) {
      try {
        r.seg.kill('SIGKILL');
        r.det.kill('SIGKILL');
        r.watcher?.close();
      } catch {
        /* ignore */
      }
      recorders.delete(id);
    }
  }

  // Start newly-enabled recorders.
  if (cfg.enabled) {
    const STAGING_ROOT = stagingRoot();
    for (const cam of cameras) {
      if (!cam.enabled || recorders.has(cam.id)) continue;
      let url: string;
      try {
        url = decrypt ? decrypt(cam.rtspUrl) : cam.rtspUrl;
      } catch {
        continue;
      }
      const stagingDir = path.join(STAGING_ROOT, cam.id);
      const ctrl = new CameraController({
        camera: cam,
        concat: concatSegments,
        storageRoot: cfg.storagePath,
        now: () => new Date(),
      });
      const seg = startSegmenter(url, stagingDir);
      // Map each new seg_NNNNN.ts to its start time (2s per segment by index).
      const watcher = fs.watch(stagingDir, async (_evt, fname) => {
        if (!fname || !String(fname).endsWith('.ts')) return;
        const idx = Number(/seg_(\d+)\.ts/.exec(String(fname))?.[1] ?? -1);
        if (idx < 0) return;
        const start = idx * 2;
        try {
          await ctrl.onSegment({ file: path.join(stagingDir, String(fname)), start, end: start + 2 });
        } catch {
          /* ignore */
        }
      });
      const det = startDetector(url, cam.sensitivity, (t) => ctrl.onMotion(t));
      recorders.set(cam.id, { seg, det, ctrl, stagingDir, watcher });
    }
  }

  // (Re)start retention timer.
  if (retentionTimer) clearInterval(retentionTimer);
  if (cfg.enabled && cfg.storagePath) {
    retentionTimer = setInterval(
      async () => {
        const v = await validateStorage(cfg.storagePath);
        if (v.ok) {
          await runRetention(cfg.storagePath, {
            freeBytes: v.freeBytes,
            floorBytes: (cfg.freeSpaceFloorGB || 20) * GB,
          }).catch(() => {});
        }
      },
      5 * 60 * 1000,
    );
    retentionTimer.unref?.();
  }
}

export function stopEngine(): void {
  for (const [, r] of recorders) {
    try {
      r.seg.kill('SIGKILL');
      r.det.kill('SIGKILL');
      r.watcher?.close();
    } catch {
      /* ignore */
    }
  }
  recorders.clear();
  if (retentionTimer) {
    clearInterval(retentionTimer);
    retentionTimer = null;
  }
}

// ---- response shaping (ported from server/cctv-api.js) ----

export interface SanitizedCamera {
  id: string;
  name: string;
  sensitivity: number;
  preRoll: number;
  postRoll: number;
  enabled: boolean;
  rtspMasked: string;
}

// Strip ciphertext + any plaintext; expose only a masked URL for display.
export function sanitizeCamerasForClient(
  cameras: Camera[] | undefined,
  decrypt: (enc: string) => string,
): SanitizedCamera[] {
  return (cameras || []).map((c) => {
    let masked = '';
    try {
      masked = maskRtsp(decrypt(c.rtspUrl));
    } catch {
      masked = '';
    }
    // Allowlist safe fields only — never spread the source camera, so neither
    // the ciphertext (rtspUrl) nor any cached plaintext can ever reach a client.
    return {
      id: c.id,
      name: c.name,
      sensitivity: c.sensitivity,
      preRoll: c.preRoll,
      postRoll: c.postRoll,
      enabled: c.enabled,
      rtspMasked: masked,
    };
  });
}

export function cctvStatusPayload(
  ff: { ffmpeg?: boolean; ffprobe?: boolean },
  storage: { ok?: boolean; reason?: string; freeBytes: number },
  engine: { enabled?: boolean; cameras?: SanitizedCamera[] },
) {
  return {
    ffmpeg: !!ff.ffmpeg,
    ffprobe: !!ff.ffprobe,
    storage: {
      ok: !!storage.ok,
      reason: storage.reason || '',
      freeGB: +(storage.freeBytes / GB).toFixed(1),
    },
    enabled: !!engine.enabled,
    cameras: engine.cameras || [],
  };
}

// Pure path helpers for CCTV clip layout + traversal safety. No I/O.
// Ported from server/cctv-paths.js.
import path from 'node:path';

const pad = (n: number): string => String(n).padStart(2, '0');

// Filesystem-safe slug for a camera folder (no separators, no dots-only).
export function safeName(name: string): string {
  const s = String(name || 'camera')
    .replace(/[^A-Za-z0-9._-]+/g, '_')
    .replace(/\.+/g, '_');
  return s.replace(/^_+|_+$/g, '') || 'camera';
}

export function dateFolder(d: Date): string {
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
}

export function clipRelPath(cameraName: string, d: Date): string {
  const hms = `${pad(d.getHours())}${pad(d.getMinutes())}${pad(d.getSeconds())}`;
  return path.join(safeName(cameraName), dateFolder(d), `clip_${hms}.mp4`);
}

// Parse "<...>/YYYY-MM-DD/clip_HHMMSS.mp4" -> Date (local). Returns null if unparseable.
export function parseClipTime(p: string): Date | null {
  const m = /(\d{4})-(\d{2})-(\d{2})[/\\]clip_(\d{2})(\d{2})(\d{2})\.mp4$/.exec(
    String(p).replace(/\\/g, '/'),
  );
  if (!m) return null;
  const [, y, mo, da, h, mi, s] = m.map(Number);
  return new Date(y, mo - 1, da, h, mi, s);
}

// True iff `target` resolves to `root` or a path inside it.
export function withinRoot(root: string, target: string): boolean {
  const r = path.resolve(root);
  const t = path.resolve(target);
  return t === r || t.startsWith(r + path.sep);
}

// Storage validation, free-space, and retention planning. Uses fs.statfs.
// Ported from server/cctv-storage.js. Node built-ins only.
import fs from 'node:fs';
import fsp from 'node:fs/promises';
import path from 'node:path';
import { withinRoot, parseClipTime } from './paths.ts';

export interface StorageInfo {
  ok: boolean;
  reason?: string;
  freeBytes: number;
  totalBytes?: number;
}

export interface ClipEntry {
  path: string;
  mtime: number;
  size: number;
  when: Date | null;
}

// Verify dir exists and is writable; report free bytes. Never throws.
export async function validateStorage(dir: string): Promise<StorageInfo> {
  try {
    const st = await fsp.stat(dir);
    if (!st.isDirectory()) return { ok: false, reason: 'Not a directory', freeBytes: 0 };
    await fsp.access(dir, fs.constants.W_OK);
    const sf = await fsp.statfs(dir);
    return { ok: true, freeBytes: sf.bsize * sf.bavail, totalBytes: sf.bsize * sf.blocks };
  } catch (err) {
    const e = err as NodeJS.ErrnoException;
    return { ok: false, reason: e.code || String(e.message || err), freeBytes: 0 };
  }
}

// Pure: given clips (oldest-deletable) + space info, return clips to delete
// (oldest first) until freeBytes would exceed floorBytes.
export function planRetention(
  clips: { path: string; mtime: number; size: number }[],
  { freeBytes, floorBytes }: { freeBytes: number; floorBytes: number },
): { path: string; mtime: number; size: number }[] {
  if (freeBytes >= floorBytes) return [];
  const sorted = [...clips].sort((a, b) => a.mtime - b.mtime);
  const out: { path: string; mtime: number; size: number }[] = [];
  let free = freeBytes;
  for (const c of sorted) {
    if (free >= floorBytes) break;
    out.push(c);
    free += c.size;
  }
  return out;
}

// Walk storage root for clip files. Returns [{path, mtime, size, when}]. Root-guarded.
export async function listClips(root: string): Promise<ClipEntry[]> {
  const out: ClipEntry[] = [];
  async function walk(dir: string): Promise<void> {
    let entries: fs.Dirent[];
    try {
      entries = await fsp.readdir(dir, { withFileTypes: true });
    } catch {
      return;
    }
    for (const e of entries) {
      const full = path.join(dir, e.name);
      if (!withinRoot(root, full)) continue;
      if (e.isDirectory()) await walk(full);
      else if (e.name.endsWith('.mp4')) {
        const st = await fsp.stat(full).catch(() => null);
        if (st) out.push({ path: full, mtime: st.mtimeMs, size: st.size, when: parseClipTime(full) });
      }
    }
  }
  await walk(root);
  return out;
}

// Delete a clip ONLY if inside root. Returns true if deleted.
export async function safeDelete(root: string, file: string): Promise<boolean> {
  if (!withinRoot(root, file)) return false;
  await fsp.rm(file, { force: true });
  return true;
}

