import type { HouseholdState, Member, Transaction } from './types';
import { mKey } from './format';

const fallbackUser: Member = { id: 0, name: '', role: 'member', status: '', color: '#10B981', init: '' };

export function getMember(state: HouseholdState, id: number): Member | undefined {
  return state.members.find((m) => m.id === id);
}
export function currentUser(state: HouseholdState, userId: number): Member {
  return getMember(state, userId) || state.members[0] || fallbackUser;
}
export function isAdmin(state: HouseholdState, userId: number): boolean {
  return currentUser(state, userId).role === 'admin';
}

export function txInMonth(state: HouseholdState, y: number, m: number): Transaction[] {
  const key = y + '-' + String(m + 1).padStart(2, '0');
  return state.transactions.filter((t) => mKey(t.date) === key);
}
export function sumType(list: Transaction[], type: 'income' | 'expense'): number {
  return list.filter((t) => t.type === type).reduce((s, t) => s + (+t.amount || 0), 0);
}
export function budgetSpent(state: HouseholdState, cat: string): number {
  const n = new Date();
  return txInMonth(state, n.getFullYear(), n.getMonth())
    .filter((t) => t.type === 'expense' && t.cat === cat)
    .reduce((s, t) => s + (+t.amount || 0), 0);
}
export function totalDebt(state: HouseholdState): number {
  return (state.debts || []).reduce((s, d) => s + (+d.balance || 0), 0);
}
export function totalMinPay(state: HouseholdState): number {
  return (state.debts || []).reduce((s, d) => s + (+d.minPayment || 0), 0);
}

// Crypto-free constant so the edge middleware can import it without pulling
// node:crypto (which auth.ts uses) into the middleware bundle.
export const SESSION_COOKIE = 'hp_session';

import { cookies } from 'next/headers';
import { SESSION_COOKIE, signToken, verifyToken } from './auth';
import { queryOne } from './db';

export interface SessionUser {
  id: string;
  email: string;
  plan: string;
  subscription_status: string | null;
  stripe_customer_id: string | null;
  current_period_end: Date | null;
}

const MAX_AGE = 60 * 60 * 24 * 30; // 30 days

export async function setSession(userId: string): Promise<void> {
  const jar = await cookies();
  jar.set(SESSION_COOKIE, signToken({ uid: userId }), {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'lax',
    path: '/',
    maxAge: MAX_AGE,
  });
}

export async function clearSession(): Promise<void> {
  const jar = await cookies();
  jar.set(SESSION_COOKIE, '', { httpOnly: true, path: '/', maxAge: 0 });
}

// Resolve the authenticated user from the session cookie, or null.
export async function getSessionUser(): Promise<SessionUser | null> {
  const jar = await cookies();
  const token = jar.get(SESSION_COOKIE)?.value;
  const payload = verifyToken(token);
  if (!payload?.uid) return null;
  return queryOne<SessionUser>(
    `SELECT id, email, plan, subscription_status, stripe_customer_id, current_period_end
     FROM users WHERE id = $1`,
    [payload.uid],
  );
}

import { queryOne, query } from './db';
import type { HouseholdState } from './seed';

// Load the authenticated user's household state (one household per user).
export async function loadState(userId: string): Promise<HouseholdState | null> {
  const row = await queryOne<{ state: HouseholdState }>(
    'SELECT state FROM households WHERE owner_user_id = $1 ORDER BY updated_at LIMIT 1',
    [userId],
  );
  return row?.state ?? null;
}

// Replace the household state wholesale (the client is the source of truth on save).
export async function saveState(userId: string, state: HouseholdState): Promise<boolean> {
  const rows = await query(
    `UPDATE households SET state = $1, updated_at = now() WHERE owner_user_id = $2 RETURNING id`,
    [state, userId],
  );
  return rows.length > 0;
}

// Pull a single collection out of the stored jsonb (read-only REST surface).
export async function collection(userId: string, key: string): Promise<unknown[]> {
  const row = await queryOne<{ items: unknown[] }>(
    `SELECT COALESCE(state -> $2, '[]'::jsonb) AS items FROM households WHERE owner_user_id = $1`,
    [userId, key],
  );
  return Array.isArray(row?.items) ? row.items : [];
}

